import{_ as a,o as e,c as r,Q as t}from"./chunks/framework.b67c47e6.js";const f=JSON.parse('{"title":"Delivery & Racks","description":"","frontmatter":{},"headers":[],"relativePath":"guide/logistics/delivery/index.md","filePath":"guide/logistics/delivery/index.md","lastUpdated":1773939149000}'),i={name:"guide/logistics/delivery/index.md"},s=t('<h1 id="delivery-racks" tabindex="-1">Delivery &amp; Racks <a class="header-anchor" href="#delivery-racks" aria-label="Permalink to &quot;Delivery &amp; Racks&quot;">​</a></h1><p>The Delivery view lets you configure how completed assemblies are arranged into physical racks for transport and storage.</p><nav class="table-of-contents"><ul><li><a href="#layout">Layout</a></li><li><a href="#rack-setup">Rack Setup</a><ul><li><a href="#adding-assemblies">Adding Assemblies</a></li><li><a href="#configuring-the-rack">Configuring the Rack</a></li><li><a href="#rack-types">Rack Types</a></li></ul></li><li><a href="#rack-traces">Rack Traces</a><ul><li><a href="#managing-rack-traces">Managing Rack Traces</a></li></ul></li></ul></nav><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><p>The delivery interface has three columns:</p><ul><li><strong>Left</strong> — List of available assemblies to load.</li><li><strong>Center</strong> — Visual grid showing the current rack arrangement.</li><li><strong>Right</strong> — Rack configuration form.</li></ul><p>Below the main area, a <strong>Rack Traces</strong> library shows previously saved rack configurations.</p><h2 id="rack-setup" tabindex="-1">Rack Setup <a class="header-anchor" href="#rack-setup" aria-label="Permalink to &quot;Rack Setup&quot;">​</a></h2><h3 id="adding-assemblies" tabindex="-1">Adding Assemblies <a class="header-anchor" href="#adding-assemblies" aria-label="Permalink to &quot;Adding Assemblies&quot;">​</a></h3><ol><li>Filter the assembly list by production line, phase, batch, or scheduled date.</li><li>Click an assembly to add it to the current rack (maximum 24 per rack).</li><li>Drag assemblies within the grid to reorder their positions.</li></ol><h3 id="configuring-the-rack" tabindex="-1">Configuring the Rack <a class="header-anchor" href="#configuring-the-rack" aria-label="Permalink to &quot;Configuring the Rack&quot;">​</a></h3><table><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Description</strong></td><td>A name or label for this rack configuration.</td></tr><tr><td><strong>Location</strong></td><td>Where the rack is stored or delivered.</td></tr><tr><td><strong>Status</strong></td><td>Current status of the rack.</td></tr><tr><td><strong>Fixed row</strong></td><td>Which row of assemblies is physically fixed to the rack frame.</td></tr></tbody></table><h3 id="rack-types" tabindex="-1">Rack Types <a class="header-anchor" href="#rack-types" aria-label="Permalink to &quot;Rack Types&quot;">​</a></h3><p>Racks can be configured as:</p><ul><li><strong>Middle</strong> — Standard rack with assemblies on both sides.</li><li><strong>Side</strong> — Assemblies loaded on one side only.</li><li><strong>Flat</strong> — Assemblies laid flat for transport.</li></ul><h2 id="rack-traces" tabindex="-1">Rack Traces <a class="header-anchor" href="#rack-traces" aria-label="Permalink to &quot;Rack Traces&quot;">​</a></h2><p>A <strong>rack trace</strong> is a saved rack configuration. Once you&#39;ve arranged assemblies in a rack, save it as a trace for:</p><ul><li>Generating <a href="/guide/reports/qr_stickers/">Rack Trace Stickers</a> for labeling.</li><li>Tracking which assemblies are in which rack during logistics.</li><li>Loading/unloading status in the <a href="/guide/viewer/">Viewer</a>.</li></ul><h3 id="managing-rack-traces" tabindex="-1">Managing Rack Traces <a class="header-anchor" href="#managing-rack-traces" aria-label="Permalink to &quot;Managing Rack Traces&quot;">​</a></h3><ul><li><strong>Save</strong> — Persist the current arrangement as a new rack trace.</li><li><strong>Edit</strong> — Modify an existing trace.</li><li><strong>Delete</strong> — Remove a trace.</li><li><strong>Reset</strong> — Clear the current setup and start fresh.</li></ul>',20),l=[s];function n(o,c,d,h,g,u){return e(),r("div",null,l)}const m=a(i,[["render",n]]);export{f as __pageData,m as default};
